.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

/* Mobile: Larger touch targets for easier dragging */
@media (max-width: 640px), (pointer: coarse) {
  .shape-tile {
    width: 96px;
    height: 96px;
    border-radius: 24px;
  }
}

const isMobile = window.matchMedia('(max-width: 640px), (pointer: coarse)').matches;

const shapeSortConfig = {
  tileSizePx: isMobile ? 96 : 72,
  dragPaddingPx: isMobile ? 20 : 6,
  snapTolerancePx: 16,
};

